import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;

import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.InOrder;

public class CSVFormatTest {

    private Appendable out;

    @BeforeEach
    public void setUp() {
        out = mock(Appendable.class);
    }

    @Test
    public void testPrintln_WithTrailingDelimiterAndRecordSeparator() throws IOException {
        CSVFormat format = CSVFormat.DEFAULT.withTrailingDelimiter(true).withRecordSeparator("\n");
        format.println(out);
        InOrder inOrder = inOrder(out);
        inOrder.verify(out).append(format.getDelimiter());
        inOrder.verify(out).append(format.getRecordSeparator());
        verifyNoMoreInteractions(out);
    }

    @Test
    public void testPrintln_WithTrailingDelimiterOnly() throws IOException {
        CSVFormat format = CSVFormat.DEFAULT.withTrailingDelimiter(true).withRecordSeparator(null);
        format.println(out);
        verify(out).append(format.getDelimiter());
        verifyNoMoreInteractions(out);
    }

    @Test
    public void testPrintln_WithRecordSeparatorOnly() throws IOException {
        CSVFormat format = CSVFormat.DEFAULT.withTrailingDelimiter(false).withRecordSeparator("\r\n");
        format.println(out);
        verify(out).append(format.getRecordSeparator());
        verifyNoMoreInteractions(out);
    }

    @Test
    public void testPrintln_WithNeitherTrailingDelimiterNorRecordSeparator() throws IOException {
        CSVFormat format = CSVFormat.DEFAULT.withTrailingDelimiter(false).withRecordSeparator(null);
        format.println(out);
        verifyNoInteractions(out);
    }

    @Test
    public void testPrintln_AppendableThrowsIOException() throws IOException {
        CSVFormat format = CSVFormat.DEFAULT.withTrailingDelimiter(true).withRecordSeparator("\n");
        doThrow(new IOException("append failed")).when(out).append(any(CharSequence.class));
        IOException thrown = assertThrows(IOException.class, () -> format.println(out));
        assertEquals("append failed", thrown.getMessage());
    }
}
